// ── Live-mode technique samples: Xylophonic ──
// Self-recorded on Yijun's harp (CC0), tuned to A=440. Xylophonic tone:
// plucked while the string is damped at its end, giving a short, bright,
// partial-rich attack (distinct from près-de-la-table). Keys are the
// *sounding* MIDI at A=440; where the fundamental was cleanly measurable
// the small residual is folded into the key (float) so playbackRate lands
// the note on pitch. The three highest strings have a weak xylophonic
// fundamental, so they are keyed to nominal MIDI. Same shape as
// HARMONIC_SAMPLES.
const XYLOPHONIC_SAMPLES = {};
XYLOPHONIC_SAMPLES[44.0] = ""; // 5Ab
XYLOPHONIC_SAMPLES[47.0] = ""; // 5Cb
XYLOPHONIC_SAMPLES[51.143] = ""; // 5Eb
XYLOPHONIC_SAMPLES[54.127] = ""; // 4Gb
XYLOPHONIC_SAMPLES[59.052] = ""; // 4Cb
XYLOPHONIC_SAMPLES[63.098] = ""; // 4Eb
XYLOPHONIC_SAMPLES[66.087] = ""; // 3Gb
XYLOPHONIC_SAMPLES[71.037] = ""; // 3Cb
XYLOPHONIC_SAMPLES[75.172] = ""; // 3Eb
XYLOPHONIC_SAMPLES[78.102] = ""; // 2Gb
XYLOPHONIC_SAMPLES[83.0] = ""; // 2Cb
XYLOPHONIC_SAMPLES[87.013] = ""; // 2Eb
XYLOPHONIC_SAMPLES[90.0] = ""; // 1Gb
XYLOPHONIC_SAMPLES[95.0] = ""; // 1Cb
XYLOPHONIC_SAMPLES[99.0] = ""; // 1Eb
XYLOPHONIC_SAMPLES[102.0] = ""; // 0Gb
const XYLOPHONIC_MIDIS = Object.keys(XYLOPHONIC_SAMPLES).map(Number).sort((a, b) => a - b);

export { XYLOPHONIC_SAMPLES, XYLOPHONIC_MIDIS };
